// -----------------------------
// Process Query Data (ROBUST)
// Parses JSON from Query Expansion AI's `text` field (often wrapped in ```json fences)
// -----------------------------

const input = $json || {};
const webhook = $('Webhook').first().json.body || {};

const userLat = webhook.user_latitude ?? null;
const userLon = webhook.user_longitude ?? null;

function toBool(v) {
  return v === true || v === 'true' || v === 1 || v === '1';
}

function parseAiPayload(raw) {
  if (!raw) return null;

  // If node already returns object, use it
  if (typeof raw === 'object') return raw;

  if (typeof raw !== 'string') return null;

  // Remove ```json ... ``` fences if present
  let s = raw.trim();
  s = s.replace(/^```json\s*/i, '').replace(/^```\s*/i, '');
  s = s.replace(/```$/i, '').trim();

  // Some models wrap JSON in extra text; try to extract first {...}
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    s = s.slice(start, end + 1);
  }

  try {
    return JSON.parse(s);
  } catch (e) {
    return null;
  }
}

// 1) Read AI JSON from `text` (your screenshot shows it's in text)
const ai = parseAiPayload(input.text) || input;

// 2) Trust AI output (do NOT override)
const intent_type   = ai.intent_type || 'place_decision';
const category_hint = ai.category_hint || null;
const person_name   = ai.person_name || null;
const location_hint = ai.location_hint || null;
const needs_near_me = toBool(ai.needs_near_me);
const urgency       = ai.urgency || 'low';
const query_language = ai.query_language || 'en';

// 3) Anchor logic
let anchor_location;

if (location_hint) {
  anchor_location = {
    type: 'query',
    location_name: location_hint,
    lat: null,
    lon: null,
    needs_geocode: true
  };
} else {
  anchor_location = {
    type: 'user',
    location_name: null,
    lat: userLat,
    lon: userLon,
    needs_geocode: false
  };
}

// 4) Output

return [{
  json: {
    intent_type,
    category_hint,
    person_name,
    location_hint,
    needs_near_me,
    urgency,
    query_language,
    anchor_location,
    expanded_terms: ai.expanded_terms || [],
    search_text: ai.search_text || ai.text || ''
  }
}];

function calculateDistance(lat1, lon1, lat2, lon2) {
  if (!lat1 || !lon1 || !lat2 || !lon2) return null;
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(lat1 * Math.PI/180) * Math.cos(lat2 * Math.PI/180) *
    Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

const webhookData = $('Webhook').first().json.body;
const userQuery = webhookData.query;
const userLat = webhookData.user_latitude || null;
const userLon = webhookData.user_longitude || null;

const queryData = $('Merge Anchor Path').first().json || {};
const queryLanguage = queryData.query_language || 'en';
const intentType = queryData.intent_type || 'place_decision';

const results = items || [];

if (results.length === 0) {
  return [{
    json: {
      q: userQuery,
      results: [],
      resultsText: "No results found.",
      has_results: false,
      query_language: queryLanguage,
      intent_type: intentType
    }
  }];
}

// ---------- Format each result ----------
// The Re-rank node already scored and sorted everything.
// This node just formats for display — NO re-sorting.
var enrichedResults = results.map(function(item) {
  var r = item.json;

  // Calculate distance for display only
  var distance_km = null;
  if (userLat && userLon && r.latitude && r.longitude) {
    distance_km = calculateDistance(userLat, userLon, r.latitude, r.longitude);
    distance_km = Math.round(distance_km * 10) / 10;
  }

  // Use _distance_km from re-rank if available (more accurate)
  if (r._distance_km !== null && r._distance_km !== undefined) {
    distance_km = Math.round(r._distance_km * 10) / 10;
  }

  // Extract URL
  var url = null;
  if (r.URL || r.url) {
    var rawUrl = r.URL || r.url;
    try {
      if (typeof rawUrl === 'string') {
        var parsed = JSON.parse(rawUrl);
        if (Array.isArray(parsed) && parsed.length > 0) url = parsed[0];
      } else if (Array.isArray(rawUrl) && rawUrl.length > 0) {
        url = rawUrl[0];
      }
    } catch (e) {
      if (typeof rawUrl === 'string' && rawUrl.startsWith('http')) {
        url = rawUrl;
      }
    }
  }

  var photo_url = r.photo_url || null;
  var added_by_name = r.added_by_name || 'Unknown';

  // Extract personal note
  var personal_note = r.personal_note || null;
  if (!personal_note && r.metadata) {
    try {
      var metadata = typeof r.metadata === 'string' ? JSON.parse(r.metadata) : r.metadata;
      personal_note = metadata.personal_note || null;
    } catch (e) {}
  }

  return {
    title: r.title || 'Untitled',
    description: r.description || '',
    enriched_description: r.enriched_description || '',
    address: r.address || null,
    added_by_name: added_by_name,
    url: url,
    photo_url: photo_url,
    personal_note: personal_note,
    distance_km: distance_km,
    latitude: r.latitude,
    longitude: r.longitude,
    // FIX: Use combined_score_v2 from re-rank (was using combined_score which no longer exists)
    relevance_score: r.combined_score_v2 || r.combined_score || 0,
    combined_score: r.combined_score_v2 || r.combined_score || 0
  };
});

// ---------- PERSON FILTER ----------
if (queryData.person_name) {
  var personName = queryData.person_name.toLowerCase();
  enrichedResults = enrichedResults.filter(function(r) {
    return r.added_by_name && r.added_by_name.toLowerCase().includes(personName);
  });

  if (enrichedResults.length === 0) {
    return [{
      json: {
        q: userQuery,
        results: [],
        resultsText: 'No recommendations found from ' + queryData.person_name,
        has_results: false,
        searched_person: queryData.person_name,
        query_language: queryLanguage,
        intent_type: intentType
      }
    }];
  }
}

// FIX: Do NOT re-sort. The Re-rank node already sorted by combined_score_v2
// which factors in: base relevance + keyword match + personal notes + proximity.
// Re-sorting here by distance was overriding the re-rank and pushing
// products/books/links to the bottom because they have no location.

// Give AI 12 candidates
var topResults = enrichedResults.slice(0, 12);

var resultsText = topResults.map(function(r, i) {
  var distDisplay = (intentType === 'content_recommendation' && !r.distance_km)
    ? ''
    : (r.distance_km !== null ? r.distance_km + 'km' : 'No location');
  var urlStr = r.url ? r.url : 'none';
  var photo = r.photo_url ? 'Has photo' : 'No photo';
  var story = r.personal_note ? 'Story: "' + r.personal_note + '"' : 'No story';
  var desc = (r.description || '').substring(0, 100);
  var distPart = distDisplay ? ' | ' + distDisplay : '';

  return (i+1) + '. ' + r.title + ' | ' + desc + distPart + ' | Added by: ' + r.added_by_name + ' | ' + story + ' | URL: ' + urlStr + ' | Photo: ' + photo;
}).join('\n');

return [{
  json: {
    q: userQuery,
    results: topResults,
    resultsText: resultsText,
    total_found: results.length,
    has_results: true,
    user_location: userLat ? { lat: userLat, lon: userLon } : null,
    searched_person: queryData.person_name || null,
    query_language: queryLanguage,
    intent_type: intentType,
    needs_near_me: queryData.needs_near_me || false
  }
}];

// Merge Response - WITH CATEGORIES (Updated for actual types)
// FIX: Normalize titles to handle invisible characters (soft hyphens, zero-width spaces)
// FIX: console.log syntax error

// ------------------
// Helpers
// ------------------
function normalizeTitle(title) {
  return (title || '')
    .toLowerCase()
    .replace(/[\u00AD\u200B\u200C\u200D\uFEFF\u00A0]/g, '') // strip soft hyphens, zero-width chars, nbsp
    .replace(/\s+/g, ' ')  // normalize whitespace
    .trim();
}

// ------------------
// Inputs
// ------------------
const formatResults = $('Format Results').first().json;
const queryData = $('Process Query Data').first().json;
const llmText = $json.text || $json.output || '';
const allResults = formatResults.results || [];
const anchorLocation = queryData.anchor_location || null;
const showGroupedResults = queryData.show_grouped_results || false;

console.log('Merge Response input:', JSON.stringify({
  resultsCount: allResults.length,
  llmTextLength: llmText.length,
  showGroupedResults: showGroupedResults
}));

// ------------------
// Parse AI response (handles JSON, markdown, or mixed)
// ------------------
var aiResponseText = '';
var keptTitles = [];
var droppedInfo = { titles: [], reasons: [] };

function extractJSON(text) {
  var jsonMatch = text.match(/\{[\s\S]*"response_text"[\s\S]*\}/);
  if (jsonMatch) {
    try {
      return JSON.parse(jsonMatch[0]);
    } catch (e) {}
  }
  try {
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

// Attempt to parse as JSON first
var parsed = extractJSON(llmText);

if (parsed && parsed.response_text) {
  aiResponseText = parsed.response_text;
  keptTitles = Array.isArray(parsed.kept_titles) ? parsed.kept_titles : [];
  droppedInfo.titles = Array.isArray(parsed.dropped_titles) ? parsed.dropped_titles : [];
  droppedInfo.reasons = Array.isArray(parsed.drop_reasons) ? parsed.drop_reasons : [];
  console.log('Parsed as JSON: kept=' + keptTitles.length + ', dropped=' + droppedInfo.titles.length);
} else {
  aiResponseText = llmText;
  var titleMatches = llmText.match(/\*\*([^*]+)\*\*/g) || [];
  keptTitles = titleMatches
    .map(function(m) { return m.replace(/\*\*/g, '').trim(); })
    .filter(function(title) {
      return allResults.some(function(r) {
        return r.title && (
          normalizeTitle(r.title).includes(normalizeTitle(title)) ||
          normalizeTitle(title).includes(normalizeTitle(r.title))
        );
      });
    });

  keptTitles = keptTitles.filter(function(v, i, a) { return a.indexOf(v) === i; });
  console.log('Fallback to markdown parsing: extractedTitles=' + keptTitles.length);
}

// If no titles extracted AND no explicit drops = parse failure → safe fallback, keep all.
// If AI explicitly dropped items (droppedInfo.titles.length > 0) but kept none = intentional 0 results.
// Do NOT restore results in that case — respect the AI decision.
if (keptTitles.length === 0 && droppedInfo.titles.length === 0) {
  keptTitles = allResults.map(function(r) { return r.title; });
  console.log('No titles extracted and no drops — parse failure, keeping all results as fallback');
} else if (keptTitles.length === 0 && droppedInfo.titles.length > 0) {
  console.log('AI explicitly dropped all results — respecting 0-match decision');
}

// ------------------
// Extract relevance explanations from response text
// ------------------
var relevanceMap = {};
var explanationPattern = /\*\*([^*]+)\*\*\s*[–—-]\s*([^(\n💭\[]+)/g;
var match;
while ((match = explanationPattern.exec(aiResponseText)) !== null) {
  var title = match[1].trim().toLowerCase();
  var explanation = match[2].trim();
  if (explanation.length > 5) {
    relevanceMap[title] = explanation;
  }
}

// ------------------
// FIX: Filter and enrich results using normalized title matching
// ------------------
var updatedResults = allResults
  .filter(function(result) {
    var dbTitle = normalizeTitle(result.title);
    return keptTitles.some(function(keptTitle) {
      var kept = normalizeTitle(keptTitle);
      return dbTitle.includes(kept) || kept.includes(dbTitle);
    });
  })
  .map(function(result) {
    var key = normalizeTitle(result.title);
    var explanation = null;
    for (var explKey in relevanceMap) {
      if (relevanceMap.hasOwnProperty(explKey)) {
        var normKey = normalizeTitle(explKey);
        if (key.includes(normKey) || normKey.includes(key)) {
          explanation = relevanceMap[explKey];
          break;
        }
      }
    }

    return {
      title: result.title,
      description: result.description,
      enriched_description: result.enriched_description,
      address: result.address,
      added_by_name: result.added_by_name,
      url: result.url,
      photo_url: result.photo_url,
      personal_note: result.personal_note,
      distance_km: result.distance_km,
      latitude: result.latitude,
      longitude: result.longitude,
      type: result.type,
      language: result.language,
      id: result.id,
      relevance_score: result.relevance_score,
      combined_score: result.combined_score,
      relevance_reason: explanation || result.relevance_reason || null
    };
  });

console.log('Final: ' + updatedResults.length + ' of ' + allResults.length + ' results');

// When nothing matched, build suggestions from the dropped results (semantically closest).
// For place/service queries: filter by distance (≤20km), sort nearest first.
// For product/advice/content: distance is irrelevant — sort by relevance score instead.
var suggestedResults = [];
if (updatedResults.length === 0 && droppedInfo.titles.length > 0) {
  var intentType = queryData.intent_type || 'place_decision';
  var isLocationBased = intentType === 'place_decision' || intentType === 'urgent_service';

  if (isLocationBased) {
    suggestedResults = allResults
      .filter(function(r) {
        return r.distance_km !== null && r.distance_km !== undefined && r.distance_km <= 20;
      })
      .sort(function(a, b) { return (a.distance_km || 999) - (b.distance_km || 999); })
      .slice(0, 4);
  } else {
    // product / advice / content_recommendation — sort by relevance score
    suggestedResults = allResults
      .sort(function(a, b) { return (b.relevance_score || 0) - (a.relevance_score || 0); })
      .slice(0, 4);
  }
  console.log('No match (' + intentType + ') — ' + suggestedResults.length + ' suggestions built from dropped results');
}

// ------------------
// Category grouping
// ------------------
var categoryMap = {
  'place': { name: 'Places', emoji: '📍' },
  'advice': { name: 'Advice', emoji: '💡' },
  'service': { name: 'Services', emoji: '🔧' },
  'product': { name: 'Products', emoji: '🛍️' }
};

var categories = [];

if (showGroupedResults) {
  var categoryGroups = {};

  updatedResults.forEach(function(result) {
    var type = (result.type || 'other').toLowerCase();
    var category = categoryMap[type] || { name: 'Other', emoji: '📌' };
    var categoryName = category.name;

    if (!categoryGroups[categoryName]) {
      categoryGroups[categoryName] = {
        name: categoryName,
        emoji: category.emoji,
        items: [],
        total_count: 0
      };
    }

    categoryGroups[categoryName].items.push(result.title);
    categoryGroups[categoryName].total_count++;
  });

  categories = Object.values(categoryGroups);
}

// ------------------
// Output
// ------------------
return [{
  json: {
    text: aiResponseText,
    results: updatedResults,
    categories: categories,
    is_grouped_display: showGroupedResults,
    q: formatResults.q,
    intent_type: queryData.intent_type,
    query_language: queryData.query_language,
    anchor_location: anchorLocation,
    has_results: updatedResults.length > 0,
    original_count: allResults.length,
    filtered_count: updatedResults.length,
    suggested_results: suggestedResults,
    _debug: {
      kept_titles: keptTitles,
      dropped_titles: droppedInfo.titles,
      drop_reasons: droppedInfo.reasons,
      parse_method: parsed ? 'json' : 'markdown_fallback'
    }
  }
}];

// Re-rank by Intent - v5 FINAL
// Fixes:
// 1. Distance filter: items without lat/lon are KEPT (not killed)
// 2. Weight redistribution: items without location/notes not unfairly penalized
// 3. Keyword matching: uses expanded_terms + item keywords + enriched_description
//    (fixes cross-language gap: Chinese description vs English query)
// 4. Removed blanket place-type filter for content_recommendation

// ---------- helpers ----------
function hasText(s) {
  return (s || '').trim().length > 0;
}

function keywordOverlapScore(queryTerms, text) {
  // queryTerms = array of search terms (from expanded_terms + original query)
  // text = combined searchable text from item
  const t = (text || '').toLowerCase();
  if (!t || queryTerms.length === 0) return 0;
  let hit = 0;
  for (const tok of queryTerms) {
    if (tok.length >= 3 && t.includes(tok)) hit++;
  }
  return Math.min(1, hit / Math.min(5, queryTerms.length));
}

function distanceKm(lat1, lon1, lat2, lon2) {
  if (lat1 == null || lon1 == null || lat2 == null || lon2 == null) return null;
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon / 2) * Math.sin(dLon / 2);
  return R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
}

// ---------- inputs ----------
const webhook = $('Webhook').first().json.body || {};
const userQuery = webhook.query || '';

const queryData = $('Process Query Data').first().json || {};
const intentType = queryData.intent_type || 'place_decision';

const mergedData = $('Merge Anchor Path').first().json || {};
const anchor = mergedData.anchor_location || queryData.anchor_location || {};

const hasAnchor = anchor.lat && anchor.lon;

// ---------- Build search terms from expanded_terms + raw query ----------
// This fixes cross-language matching: Chinese description won't match "shampoo"
// but the item's keywords field WILL, and expanded_terms like "hair care" WILL
// match the enriched_description
const rawTokens = (userQuery || '').toLowerCase().split(/[\s,.;!?]+/).filter(Boolean);
const expandedTerms = (queryData.expanded_terms || []).map(function(t) { return t.toLowerCase(); });
const allTermsSet = {};
rawTokens.forEach(function(t) { allTermsSet[t] = true; });
expandedTerms.forEach(function(t) {
  // expanded_terms can be multi-word like "hair care" — split them too
  t.split(/\s+/).forEach(function(w) { allTermsSet[w] = true; });
});
const searchTerms = Object.keys(allTermsSet);

// ---------- normalize ----------
let results = items.map(function(i) { return i.json; });

// ── Odin Trust Layer: Privacy filter ────────────────────────
// Allowed: own items, direct friends (non-private), FOF (friends-visibility, anonymised)
// The RPC already gates at DB level; this is a defence-in-depth layer in n8n.
const webhook_body = $('Webhook').first().json.body || {};
const selfUserId = webhook_body.user_id || null;
const allowedUserIds = new Set(webhook_body.allowed_user_ids || []);
const friendIds = new Set(webhook_body.friend_ids || []);

results = results.filter(function(r) {
  const owner = r.added_by || null;
  // FOF items: RPC returns them with trust_level='extended_circle' and added_by=null
  if (!owner && r.trust_level === 'extended_circle') return true;
  // Private items: only owner can see them
  if (r.visibility === 'private' && owner !== selfUserId) return false;
  // Direct friends: allowed if in allowedUserIds
  if (allowedUserIds.size > 0 && owner && allowedUserIds.has(owner)) return true;
  // FOF with owner still set: allow if trust_level says extended_circle
  if (r.trust_level === 'extended_circle') return true;
  // Unknown owner with no trust signal: only keep if in allowedUserIds
  if (allowedUserIds.size > 0 && owner && !allowedUserIds.has(owner)) return false;
  return true;
});

// Anonymise FOF items: clear identity fields so AI never sees them
results = results.map(function(r) {
  if (r.trust_level === 'extended_circle') {
    r = Object.assign({}, r);
    r.added_by      = null;
    r.added_by_name = 'Someone in your circle';
    r.personal_note = null;
    return r;
  }
  return r;
});

// Strip personal_note from items not owned by searcher or direct friends
results = results.map(function(r) {
  const owner = r.added_by || null;
  const isFriend = owner && friendIds.has(owner);
  const isOwn    = owner && owner === selfUserId;
  if (!isFriend && !isOwn) {
    r = Object.assign({}, r);
    r.personal_note = null;  // never leak notes to non-friends
  }
  return r;
});
// ── End Privacy Filter ───────────────────────────────────────


// No type filter for content_recommendation.
// Hybrid search already scored relevance — trust it.

// ---------- distance thresholds ----------
const MAX_DISTANCE_BY_INTENT = {
  advice_synthesis: 180,
  place_decision: 30,
  urgent_service: 15,
  recall: 50,
  content_recommendation: 999
};

const MAX_KM = MAX_DISTANCE_BY_INTENT[intentType] || 50;

// Detect special occasion queries
const isSpecialOccasion = userQuery.toLowerCase().match(/romantic|anniversary|birthday|celebration|date night|special occasion|propose|engagement/);

// ---------- scoring ----------
results = results.map(function(r) {
  // Build rich searchable text: title + description + note + enriched + keywords
  var keywordsText = '';
  if (Array.isArray(r.keywords)) {
    keywordsText = r.keywords.join(' ');
  } else if (typeof r.keywords === 'string') {
    keywordsText = r.keywords;
  }
  var text = (r.title || '') + ' ' + (r.description || '') + ' ' +
    (r.personal_note || '') + ' ' + (r.enriched_description || '') + ' ' + keywordsText;

  var base = Number(r.combined_score || r.relevance_score || 0);
  var kw = keywordOverlapScore(searchTerms, text);
  var hasNote = hasText(r.personal_note);

  // Calculate distance only if we have anchor AND item has location
  var dkm = null;
  if (hasAnchor && r.latitude && r.longitude) {
    dkm = distanceKm(anchor.lat, anchor.lon, r.latitude, r.longitude);
  }

  // Distance filter: only for non-content, non-person queries
  // Only filter items that HAVE a location but are TOO FAR
  // Items WITHOUT location (products, links, online) → KEEP
  if (intentType !== 'content_recommendation' && !queryData.person_name) {
    if (dkm !== null && dkm > MAX_KM) {
      return null;
    }
  }

  // Calculate proximity (0 for items without location)
  var proximity = dkm !== null ? Math.max(0, 1 - dkm / MAX_KM) : 0;

  // ---------- Base weights ----------
  var baseWeight = 0.55;
  var keywordWeight = 0.20;
  var noteWeight = 0.15;
  var proximityWeight = 0.10;

  if (intentType === 'content_recommendation') {
    proximityWeight = 0.0;
    keywordWeight = 0.35;
  } else if (isSpecialOccasion) {
    proximityWeight = 0.05;
    keywordWeight = 0.25;
  }

  // Redistribute unused weights back to base
  if (dkm === null) {
    baseWeight += proximityWeight;
    proximityWeight = 0;
  }
  if (!hasNote) {
    baseWeight += noteWeight * 0.5;
    noteWeight *= 0.5;
  }

  var score =
    baseWeight * base +
    keywordWeight * kw +
    noteWeight * (hasNote ? 1 : 0) +
    proximityWeight * proximity;

  // Distance tier for "near me" queries
  var distanceTier = null;
  if (queryData.needs_near_me && dkm !== null) {
    if (dkm <= 5) distanceTier = 'nearby';
    else if (dkm <= 15) distanceTier = 'reachable';
    else distanceTier = 'far';
  }

  return {
    title: r.title,
    type: r.type,
    description: r.description,
    personal_note: r.personal_note,
    enriched_description: r.enriched_description,
    keywords: r.keywords,
    address: r.address,
    latitude: r.latitude,
    longitude: r.longitude,
    URL: r.URL,
    photo_url: r.photo_url,
    added_by_name: r.added_by_name,
    language: r.language,
    id: r.id,
    saves_count: r.saves_count,
    metadata: r.metadata,
    combined_score_v2: score,
    _distance_km: dkm,
    _distance_tier: distanceTier,
    _keyword_score: kw,
    _base_score: base
  };

}).filter(Boolean);

// ---------- sort + cap ----------
results.sort(function(a, b) { return b.combined_score_v2 - a.combined_score_v2; });

var CAP = intentType === 'urgent_service' ? 6 : intentType === 'recall' ? 5 : 8;

return results.slice(0, CAP).map(function(r) { return { json: r }; });

// ============================================
// Merge Anchor Path
// Purpose: Combine geocoded OR user location
// ============================================

const queryData = $('Process Query Data').first().json;
const anchor = queryData.anchor_location;

// Get all inputs (2 paths merge here)
const inputs = $input.all();

// Find geocoding result (if exists)
const geocodeResult = inputs.find(i => 
  i.json.latitude && 
  i.json.longitude && 
  i.json.source
);

if (geocodeResult) {
  // Path 1: Geocoded location
  anchor.lat = geocodeResult.json.latitude;
  anchor.lon = geocodeResult.json.longitude;
  anchor.resolved_name = geocodeResult.json.resolved_name || anchor.location_name;
  console.log(`✅ Geocoded: ${anchor.location_name} → ${anchor.lat}, ${anchor.lon}`);

} else if (!anchor.needs_geocode) {
  // Path 2: User location (already set in Process Query Data)
  console.log(`✅ Using user location: ${anchor.lat}, ${anchor.lon}`);

} else {
  // Path 3: Geocoding failed - fallback to user location
  const webhook = $('Webhook').first().json.body;
  anchor.lat = webhook.user_latitude || null;
  anchor.lon = webhook.user_longitude || null;
  anchor.type = 'fallback';
  console.log(`⚠️ Geocoding failed, using fallback: ${anchor.lat}, ${anchor.lon}`);
}

// Extract search text for embedding
const queryExpansion = $('Query Expansion AI').first().json;
let searchText;

try {
  const parsed = typeof queryExpansion.text === 'string' 
    ? JSON.parse(queryExpansion.text.replace(/```json\n?|```\n?/g, '').trim())
    : queryExpansion;
  searchText = parsed.search_text || parsed.text || queryExpansion.text;
} catch (e) {
  searchText = queryExpansion.text || queryExpansion.search_text;
}

// Output for embedding generation
return [{
  json: {
    ...queryData,
    anchor_location: anchor,
    text: searchText
  }
}];

const webhook = $json.body || {};
const userQuery = webhook.query || '';
const userId = webhook.user_id || '4c81734b-63a1-44fb-9c54-ed14760e16e7';
const isVoiceRequest = webhook.is_voice || false;

let sessionId;

if (isVoiceRequest) {
  sessionId = `voice_${userId}_${Date.now()}`;
} else {
  sessionId = webhook.session_id || `session_${userId}_${new Date().toISOString().split('T')[0]}`;
}

const conversationEntry = {
  user_id: userId,
  session_id: sessionId,
  role: 'user',
  message: userQuery,
  metadata: {
    user_latitude: webhook.user_latitude,
    user_longitude: webhook.user_longitude,
    is_voice: isVoiceRequest,
    timestamp: new Date().toISOString()
  }
};

return [{
  json: {
    ...webhook,
    session_id: sessionId,
    conversation_entry: conversationEntry
  }
}];

// Save Assistant Response to Memory
const mergeData = $json;
const sessionData = $('Prepare Session').first().json;
const sessionId = sessionData.session_id;
const userId = $('Webhook').first().json.body.user_id || '4c81734b-63a1-44fb-9c54-ed14760e16e7';

// Create storage object (flat structure for HTTP node)
const storageData = {
  user_id: userId,
  session_id: sessionId,
  role: 'assistant',
  message: mergeData.text || '',
  metadata: {
    results_count: mergeData.filtered_count || 0,
    intent_type: mergeData.intent_type,
    query_language: mergeData.query_language,
    timestamp: new Date().toISOString()
  }
};

// Return BOTH: storage data AND original response
return [{
  json: {
    // For HTTP storage node
    ...storageData,
    // For final response (prefixed to avoid conflicts)
    _response: mergeData
  }
}];

const mergeResponse = $('Merge Response').first().json;
const webhook = $('Webhook').first().json.body;
const isVoiceRequest = webhook.is_voice || false;

if (isVoiceRequest) {
  // VOICE-OPTIMIZED RESPONSE
  const results = mergeResponse.results || [];
  let voiceText = '';
  let mapsUrl = null;

  if (results.length === 0) {
    voiceText = "I didn't find anything matching that.";

  } else if (results.length === 1) {
    const r = results[0];
    voiceText = `I found ${r.title}. `;

    // Add "Added by" info
    if (r.added_by_name) {
      voiceText += `Added by ${r.added_by_name}. `;
    }

    if (r.distance_km) {
      if (r.distance_km < 1) {
        voiceText += `It's ${Math.round(r.distance_km * 1000)} meters away. `;
      } else {
        voiceText += `It's ${r.distance_km.toFixed(1)} kilometers away. `;
      }
    }

    // Generate Google Maps link for single result
    if (r.latitude && r.longitude) {
      mapsUrl = `https://www.google.com/maps/search/?api=1&query=${r.latitude},${r.longitude}`;
    } else if (r.address) {
      mapsUrl = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(r.address)}`;
    }

  } else {
    // Multiple results
    const top = results[0];
    const cleanTitle = top.title.split(' - ')[0];

    voiceText = `I found ${results.length} options. Top pick is ${cleanTitle}`;

    // Add "Added by" for top result
    if (top.added_by_name) {
      voiceText += `, added by ${top.added_by_name}`;
    }

    if (top.distance_km) {
      voiceText += `, ${top.distance_km.toFixed(1)} kilometers away`;
    }

    voiceText += '.';

    // Generate Google Maps link for top result
    if (top.latitude && top.longitude) {
      mapsUrl = `https://www.google.com/maps/search/?api=1&query=${top.latitude},${top.longitude}`;
    } else if (top.address) {
      mapsUrl = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(top.address)}`;
    }
  }

  return [{
    json: {
      voice_text: voiceText,
      maps_url: mapsUrl,
      results: results.slice(0, 3),
      has_results: results.length > 0
    }
  }];

} else {
  // WEB INTERFACE - Keep original
  return [{
    json: mergeResponse
  }];
}

// ✅ NEW NODE: Prepare Response Context
// Purpose: Format conversation history for Generate Response node

const formatResults = $('Format Results').first().json;
const conversationHistory = $('Fetch Conversation History').all();

// Format conversation history (excluding current message)
let historyText = 'No previous messages';

if (conversationHistory.length > 0) {
  historyText = conversationHistory
    .map(item => `${item.json.role}: ${item.json.message}`)
    .reverse()
    .join('\n');
}

return [{
  json: {
    ...formatResults,
    conversation_history: historyText
  }
}];
